// frontend/src/services/api.js
import axios from 'axios';

const API = '/api'; 
const PRED = process.env.REACT_APP_PREDICTION_URL || 'http://localhost:8001';

// ─── Places ──────────────────────────────────────────────
export const getPlaces = (category = 'all', search = '') =>
  axios.get(`${API}/places`, { params: { category, search } }).then(r => r.data);

export const getPlaceById = (id) =>
  axios.get(`${API}/places/${id}`).then(r => r.data);

export const getNearbyPlaces = (lat, lng, category = 'all') =>
  axios.get(`${API}/places/search/nearby`, { params: { lat, lng, category } }).then(r => r.data);

export const addPlace = (data) =>
  axios.post(`${API}/places`, data).then(r => r.data);

// ─── Prediction ───────────────────────────────────────────
export const getPrediction = (place_id, target_hour = null, target_day = null) =>
  axios.post(`${PRED}/predict`, { place_id: String(place_id), target_hour, target_day })
    .then(r => r.data)
    .catch(() => ({
      crowd_level: 'Medium',
      active_users: 0,
      waiting_time: 'N/A',
      estimated_cost: '₹0',
      best_time: 'N/A',
      confidence: 'low'
    }));

export const getBestTimes = (place_id) =>
  axios.get(`${PRED}/best-time/${place_id}`).then(r => r.data).catch(() => ({}));

// ─── Check-ins ───────────────────────────────────────────
export const checkIn = (place_id) =>
  axios.post(`${API}/checkins/in`, { place_id }).then(r => r.data);

export const checkOut = (place_id, amount_spent) =>
  axios.post(`${API}/checkins/out`, { place_id, amount_spent }).then(r => r.data);

export const getMyActiveCheckin = () =>
  axios.get(`${API}/checkins/my-active`).then(r => r.data);

export const getMyHistory = () =>
  axios.get(`${API}/checkins/my-history`).then(r => r.data);

export const getActiveCount = (place_id) =>
  axios.get(`${API}/checkins/active/${place_id}`).then(r => r.data);
